class PlayerTurnHandler {
  private game: Game;
  private bga: Bga;

  constructor(game: Game, bga: Bga) {
    this.game = game;
    this.bga = bga;
  }

  onEnteringState(args: any, isCurrentPlayerActive: boolean) {
    if (!isCurrentPlayerActive) return;
    // Set up UI for this state
    this.bga.statusBar.addActionButton(
      _('Pass'),
      () => this.bga.actions.performAction('action_pass')
    );
  }

  onLeavingState(args: any, isCurrentPlayerActive: boolean) {
    // Clean up UI
  }
}

// In your Game class constructor:
constructor(bga: Bga) {
  super(bga);
  this.bga.states.register("PlayerTurn", new PlayerTurnHandler(this, bga));
}

// In a state handler's onEnteringState:
onEnteringState(args: any, isCurrentPlayerActive: boolean) {
  if (!isCurrentPlayerActive) return;

  // Highlight clickable elements
  document.querySelectorAll('.card').forEach((node) => {
    node.classList.add('active_slot');
    node.addEventListener('click', this.onCardClick);
  });

  // Add action buttons to the status bar
  this.bga.statusBar.addActionButton(
    _('Pass'),
    () => this.bga.actions.performAction('action_pass')
  );
}

onLeavingState(args: any, isCurrentPlayerActive: boolean) {
  // Clean up
  document.querySelectorAll('.active_slot').forEach((node) => {
    node.classList.remove('active_slot');
    node.removeEventListener('click', this.onCardClick);
  });
}

onCardClick = (event: Event) => {
  const id = (event.currentTarget as HTMLElement).id;
  this.bga.actions.performAction('action_playCard', { id });
};

